function B4DUI.Scoreboard.Open() if IsValid(B4DUI.Scoreboard.Frame) then return end; local f=B4DUI.UI.CreateFrame("B4D Scoreboard",ScrW()*.72,ScrH()*.74); B4DUI.Scoreboard.Frame=f; local list=f:Add("DScrollPanel"); list:SetPos(24,86); list:SetSize(f:GetWide()-48,f:GetTall()-110); B4DUI.UI.SkinScroll(list); for _,p in ipairs(player.GetAll()) do local row=list:Add("DButton"); row:Dock(TOP); row:DockMargin(0,0,0,6); row:SetTall(42); row:SetText(""); row.Paint=function(_,w,h) draw.RoundedBox(8,0,0,w,h,B4DUI.Color("panel2")); draw.SimpleText(p:Nick(),"B4D.Body",14,11,B4DUI.Color("text")); draw.SimpleText(team.GetName(p:Team()) or "","B4D.Small",260,13,B4DUI.Color("muted")); draw.SimpleText(p:Ping().." ms","B4D.Small",w-72,13,B4DUI.Color("muted")) end end end
